const RESPUESTAS = [
  {
    escenario: "PAGO_CONFIRMADO",
    textos: [
      "Buenos días, les confirmamos que el pago fue realizado ayer. Pueden verificarlo en sus cuentas en los próximos días.",
      "Hola, el pago ya está cursado desde esta mañana. Quedo a su disposición para cualquier consulta.",
      "Buenas tardes, acabo de confirmar con nuestro departamento financiero que la transferencia se realizó el lunes."
    ]
  },
  {
    escenario: "PROMESA_PAGO",
    textos: [
      "Disculpen el retraso. Procederemos al pago la próxima semana, en cuanto tengamos la aprobación interna.",
      "Lo tenemos en agenda, lo abonaremos antes del viernes.",
      "Estamos en proceso de aprobación interna, en máximo 3 días realizamos el pago."
    ]
  },
  {
    escenario: "DISPUTA",
    textos: [
      "Esta factura ya fue abonada el mes pasado. Por favor revisen sus registros antes de volver a contactarnos.",
      "Creemos que hay un error, este importe ya fue satisfecho. Les adjuntamos el justificante.",
      "No entendemos este recordatorio, el pago está confirmado por nuestra parte desde hace semanas."
    ]
  },
  {
    escenario: "SOLICITUD_COPIA",
    textos: [
      "¿Podríais enviarnos de nuevo la factura? No la hemos recibido correctamente y necesitamos revisarla.",
      "Necesitamos una copia de la factura para poder tramitar el pago internamente.",
      "Por favor reenviad la factura a nuestro departamento de administración, no la localizamos en el sistema."
    ]
  },
  {
    escenario: "SIN_RESPUESTA",
    textos: [null]
  }
];

const PESOS = [30, 30, 10, 15, 15];

function elegirEscenario() {
  const total = PESOS.reduce((a, b) => a + b, 0);
  let random = Math.random() * total;
  for (let i = 0; i < RESPUESTAS.length; i++) {
    random -= PESOS[i];
    if (random <= 0) {
      const textos = RESPUESTAS[i].textos;
      const texto = textos[Math.floor(Math.random() * textos.length)];
      return { escenario: RESPUESTAS[i].escenario, texto };
    }
  }
  const textos = RESPUESTAS[0].textos;
  return { escenario: RESPUESTAS[0].escenario, texto: textos[0] };
}

const items_filtrados = items.filter(() => Math.random() < 0.4);

return items_filtrados.map(item => {
  const escenario = elegirEscenario();
  return {
    json: {
      ...item.json,
      escenario: escenario.escenario,
      texto_respuesta: escenario.texto,
      enviar: escenario.escenario !== "SIN_RESPUESTA"
    }
  };
});
